mapper.select:
SELECT * FROM (
	SELECT ROWNUM AS rn, A.* FROM(
		SELECT AT.*, C.note AS category_name
		FROM attach_file AT
		LEFT JOIN common_code C ON AT.file_code = C.code_id

			AT.file_use_yn = 'g001'

				AND AT.project_id = #{projectId}


		ORDER BY AT.upload_date DESC
	) A
)
WHERE rn BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*) FROM attach_file

	file_use_yn = 'g001'
	 AND project_id = #{projectId} 
	 AND original_name LIKE '%' || #{originalName} || '%'

	 AND upload_user_id LIKE '%' || #{uploadUserId} || '%'

	 AND TO_CHAR(upload_date, 'YYYY-MM-DD') >= #{startDate}


		AND TO_CHAR(upload_date, 'YYYY-MM-DD')  <= 
		#{endDate}

SELECT COUNT(*)
FROM project_member pm
JOIN team_member tm ON pm.team_member_id = tm.team_member_id
WHERE pm.project_id = #{projectId}
AND tm.user_id = #{userId}

mapper.insert:

	SELECT
	'ATTACH_FILE_'
	|| to_char(sysdate, 'YYMM')
	|| '_'
	|| lpad(
	nvl(max(to_number(substr(file_id, -4))), 0) + 1,
	4,
	'0'
	)
	FROM
	attach_file
	WHERE file_id LIKE 'ATTACH_FILE_' || to_char(sysdate,
	'YYMM') || '_%'


INSERT INTO attach_file(
file_id
, project_id
, version_id
, file_code
,
original_name
, stored_name
, file_path
, file_size
, upload_user_id
,
upload_date
, file_version
, file_use_yn
)
VALUES(
#{fileId}
, #{projectId}
, #{versionId}
, #{fileCode}
, #{originalName}
,
#{storedName}
,
#{filePath}
, #{fileSize}
, #{uploadUserId}

,

	#{uploadDate}
	SYSDATE

, #{fileVersion}
, #{fileUseYn}
)

mapper.update:
UPDATE attach_file
project_id = #{projectId}, version_id = #{versionId}, file_code = #{fileCode}, original_name = #{originalName}, stored_name = #{storedName}, file_path = #{filePath}, file_size = #{fileSize}, file_version = #{fileVersion}, file_use_yn = #{fileUseYn}, connect_address = #{connectAddress},
WHERE file_id = #{fileId}

UPDATE attach_file
SET file_use_yn = #{fileUseYn}
WHERE file_id = #{fileId}
